#!/usr/bin/env node
/**
 * patch-android-kotlin.mjs
 *
 * Capacitor 8's default `android/build.gradle` template (the project-
 * level build script generated by `npx cap add android`) does not
 * include the Kotlin Gradle plugin on the buildscript classpath.
 *
 * Our local plugins under `native-plugins/` (e.g. capacitor-chat-bubbles,
 * capacitor-native-call-ui) declare `apply plugin: 'kotlin-android'` in
 * their per-module `build.gradle`, which fails Gradle configuration
 * with:
 *
 *   > Plugin with id 'kotlin-android' not found.
 *
 * This script idempotently injects the Kotlin Gradle plugin classpath
 * into the project-level `buildscript { dependencies { ... } }` block
 * so those `apply plugin: 'kotlin-android'` calls resolve.
 *
 * It pins `KOTLIN_VERSION` to a value compatible with the Android
 * Gradle Plugin shipped by Capacitor 8 (AGP 8.x). 1.9.24 is the
 * highest stable Kotlin release that AGP 8.0–8.5 was tested against
 * and is widely deployed; bump as Capacitor upgrades AGP.
 *
 * Idempotent: re-running is a no-op once the marker comment is
 * present.
 *
 * Used by `.github/workflows/android-build.yml`.
 */

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

const scriptFile = fileURLToPath(import.meta.url);
const projectRoot = path.resolve(path.dirname(scriptFile), "..", "..");
const buildGradlePath = path.join(projectRoot, "android", "build.gradle");

const MARKER = "// === VEX kotlin classpath (injected by CI) ===";
const KOTLIN_VERSION = "1.9.24";

// Insert into the existing `dependencies { ... }` block inside the
// top-level `buildscript { ... }`. We match the closing brace of
// that inner dependencies block and inject our classpath line just
// before it.
const CLASSPATH_LINE = `        ${MARKER}
        classpath "org.jetbrains.kotlin:kotlin-gradle-plugin:${KOTLIN_VERSION}"`;

function injectIntoBuildscriptDeps(gradle) {
    // Greedy search for the FIRST `buildscript { ... dependencies { ... } }`
    // block and inject our line before its closing brace.
    // Capacitor's template puts only one buildscript block at the top.
    const re = /(buildscript\s*\{[\s\S]*?dependencies\s*\{)([\s\S]*?)(\n\s*\})/m;
    const match = gradle.match(re);
    if (!match) {
        return null;
    }
    const [whole, prefix, body, closing] = match;
    if (body.includes(MARKER)) {
        return gradle; // already patched
    }
    const replacement = `${prefix}${body}\n${CLASSPATH_LINE}${closing}`;
    return gradle.replace(whole, replacement);
}

function main() {
    if (!existsSync(buildGradlePath)) {
        console.error(`[patch-kotlin] ${buildGradlePath} not found.`);
        console.error("[patch-kotlin] Run `npx cap add android && npx cap sync android` first.");
        process.exit(1);
    }

    const gradle = readFileSync(buildGradlePath, "utf8");

    if (gradle.includes(MARKER)) {
        console.log("[patch-kotlin] Marker already present — nothing to do (idempotent).");
        return;
    }

    const patched = injectIntoBuildscriptDeps(gradle);
    if (patched === null) {
        console.error("[patch-kotlin] Could not locate `buildscript { dependencies { ... } }` block.");
        console.error("[patch-kotlin] Capacitor template may have changed. Inspect android/build.gradle.");
        process.exit(1);
    }

    writeFileSync(buildGradlePath, patched);
    console.log(`[patch-kotlin] Injected Kotlin Gradle plugin classpath (${KOTLIN_VERSION}) into android/build.gradle.`);
}

main();
